<?php namespace SmartChat; class REST { public function __construct() { add_action("rest_api_init", array($this, "register_routes")); } public function register_routes() { register_rest_route("hmsc/v1", "/ask", array("methods" => "POST", "callback" => array($this, "handle_ask"), "permission_callback" => "__return_true")); } public function handle_ask($request) { $message = sanitize_textarea_field($request->get_param("message")); if (empty($message)) { return new \WP_Error("invalid_message", "Message is required", array("status" => 400)); } $router = new Router(); return $router->process_query($message); } }
